#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int hasOdd = 0, hasEven = 0; // 1-indexed parity
        for (int i = 0; i < N; ++i) {
            if (s[i] == '1') {
                if ((i % 2) == 0) hasOdd = 1; // position i+1 is odd
                else hasEven = 1; // position i+1 is even
            }
        }
        if (hasOdd && hasEven) printf("1\n");
        else printf("2\n");
    }
    return 0;
}

