            for (int i = 0; i < N; i++) {
                if (s.charAt(i) == '1') {
                    if (i % 2 == 0) hasOdd = true; // position i+1 is odd
                    else hasEven = true; // position i+1 is even
                }
            }
            out.append((hasOdd && hasEven) ? 1 : 2).append('\n');
        }
        System.out.print(out.toString());
    }
