#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        has_odd = has_even = False  # 1-indexed parity
        for i,ch in enumerate(s):
            if ch == '1':
                if i % 2 == 0:
                    has_odd = True   # position i+1 is odd
                else:
                    has_even = True  # position i+1 is even
        out_lines.append('1' if (has_odd and has_even) else '2')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

